import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';
import { LazyLoadImage } from 'react-lazy-load-image-component';
import 'react-lazy-load-image-component/src/effects/blur.css';
import toast from 'react-hot-toast';
import { useCart } from '../context/CartContext';
import { productImageUrl } from '../lib/productImage';

const Cart = () => {
  const navigate = useNavigate();
  const {
    cart,
    cartState,
    updateCartItem,
    removeFromCart,
    clearCart,
    applyCoupon,
    removeCoupon,
    getSubtotal,
    fetchCart
  } = useCart();
  const [couponCode, setCouponCode] = useState('');
  const [deliveryOption] = useState('standard');

  const totals = cartState.totals;

  const handleApplyCoupon = async () => {
    const code = couponCode.trim();
    if (!code) {
      toast.error('Enter a coupon code');
      return;
    }
    await applyCoupon(code);
  };

  const handleCheckout = () => {
    if (!cart.length) {
      toast.error('Your cart is empty');
      return;
    }
    navigate('/checkout');
  };

  return (
    <>
      <Helmet>
        <title>Cart | Nova Shop</title>
      </Helmet>
      <header className="page-header">
        <div className="container">
          <h1>Shopping cart</h1>
          <ol className="breadcrumb">
            <li>
              <Link to="/">Home</Link>
            </li>
            <li>
              <Link to="/shop">Shop</Link>
            </li>
            <li className="active">Cart</li>
          </ol>
        </div>
      </header>

      <main className="cart-page" id="main-content">
        <div className="container">
          <div className="cart-layout">
            <div>
              <div
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'space-between',
                  marginBottom: '1.25rem'
                }}
              >
                <h2 style={{ fontSize: '1.4rem' }}>Your items</h2>
                {cart.length > 0 && (
                  <button
                    type="button"
                    onClick={() => clearCart()}
                    style={{
                      fontSize: '0.8rem',
                      color: 'var(--gray)',
                      background: 'none',
                      border: 'none',
                      cursor: 'pointer',
                      textDecoration: 'underline'
                    }}
                  >
                    Clear cart
                  </button>
                )}
              </div>

              <div className="cart-items">
                {cart.length === 0 ? (
                  <div className="empty-cart animate-in">
                    <div className="empty-icon">🛒</div>
                    <h3>Your cart is empty</h3>
                    <p style={{ marginBottom: '1.5rem' }}>Browse the shop to add products.</p>
                    <Link to="/products" className="btn btn-primary">
                      Start shopping
                    </Link>
                  </div>
                ) : (
                  cart.map((line, idx) => {
                    const p = line.product || {};
                    const ref = p._id || line.product;
                    const img = productImageUrl(p);
                    return (
                      <div
                        key={String(ref)}
                        className="cart-item"
                        style={{ animationDelay: `${idx * 0.08}s` }}
                      >
                        <div className="cart-item-img">
                          {img ? (
                            <LazyLoadImage
                              src={img}
                              alt={p.name}
                              className="cart-item-img__photo"
                              effect="blur"
                            />
                          ) : (
                            <span className="cart-item-img__emoji">📦</span>
                          )}
                        </div>
                        <div className="cart-item-info">
                          <Link to={`/shop/${p.slug || ''}`} className="cart-item-name-link">
                            <div className="cart-item-name">{p.name}</div>
                          </Link>
                          <div className="qty-control">
                            <button
                              type="button"
                              className="qty-btn"
                              onClick={() => updateCartItem(ref, line.quantity - 1)}
                            >
                              −
                            </button>
                            <span className="qty-display">{line.quantity}</span>
                            <button
                              type="button"
                              className="qty-btn"
                              onClick={() => updateCartItem(ref, line.quantity + 1)}
                            >
                              +
                            </button>
                          </div>
                        </div>
                        <div className="cart-item-price">
                          <div className="cart-item-total">
                            £{Number(line.lineTotal ?? line.price * line.quantity).toFixed(2)}
                          </div>
                          <div
                            style={{
                              fontSize: '0.78rem',
                              color: 'var(--gray)',
                              marginTop: '0.2rem'
                            }}
                          >
                            £{Number(line.price).toFixed(2)} each
                          </div>
                          <button
                            type="button"
                            className="cart-item-remove"
                            onClick={() => removeFromCart(ref)}
                          >
                            ✕ Remove
                          </button>
                        </div>
                      </div>
                    );
                  })
                )}
              </div>
            </div>

            <div>
              <div className="cart-summary">
                <h3>Order summary</h3>

                <div className="coupon-group">
                  <input
                    type="text"
                    placeholder="COUPON CODE"
                    value={couponCode}
                    onChange={(e) => setCouponCode(e.target.value.toUpperCase())}
                    maxLength={32}
                  />
                  <button type="button" className="btn btn-gold btn-sm" onClick={handleApplyCoupon}>
                    Apply
                  </button>
                </div>
                {cartState.coupon && (
                  <p className="coupon-applied">
                    {cartState.coupon.code} applied
                    <button
                      type="button"
                      className="link-btn"
                      onClick={() => removeCoupon()}
                    >
                      Remove
                    </button>
                  </p>
                )}

                <div className="summary-row">
                  <span className="label">Subtotal</span>
                  <span className="value">£{getSubtotal().toFixed(2)}</span>
                </div>
                {totals && (
                  <>
                    <div className="summary-row">
                      <span className="label">Discount</span>
                      <span className="value" style={{ color: '#34d399' }}>
                        −£{Number(totals.discountAmount || 0).toFixed(2)}
                      </span>
                    </div>
                    <div className="summary-row total">
                      <span className="label">Total</span>
                      <span className="value">£{Number(totals.total || 0).toFixed(2)}</span>
                    </div>
                  </>
                )}

                <button
                  type="button"
                  className="btn btn-gold btn-full"
                  style={{ marginTop: '1.5rem' }}
                  onClick={handleCheckout}
                  disabled={!cart.length}
                >
                  Proceed to checkout →
                </button>
                <p className="checkout-hint">
                  Delivery option (£{deliveryOption}) can be chosen at checkout. Totals include tax
                  where applicable.
                </p>
              </div>
            </div>
          </div>
        </div>
      </main>
    </>
  );
};

export default Cart;
